3	import { RegistryNotConfiguredError } from "@/src/registry/errors"
4	import { parseRegistryAndItemFromString } from "@/src/registry/parser"
5	import { isLocalFile, isUrl } from "@/src/registry/utils"
6	import { validateRegistryConfig } from "@/src/registry/validator"
7	import { registryConfigItemSchema } from "@/src/schema"
8	import { Config } from "@/src/utils/get-config"
9	import { z } from "zod"
10	
11	const NAME_PLACEHOLDER = "{name}"
12	const STYLE_PLACEHOLDER = "{style}"
13	const ENV_VAR_PATTERN = /\${(\w+)}/g
14	const QUERY_PARAM_SEPARATOR = "?"
15	const QUERY_PARAM_DELIMITER = "&"
16	
17	function isLocalPath(path: string) {
18	  return path.startsWith("./") || path.startsWith("/")
19	}
20	
21	export function buildUrlAndHeadersForRegistryItem(
22	  name: string,
23	  config?: Config
24	) {
25	  let { registry, item } = parseRegistryAndItemFromString(name)
26	
27	  // If no registry prefix, check if it's a URL or local path.
28	  // These should be handled directly, not through a registry.
29	  if (!registry) {
30	    if (isUrl(name) || isLocalFile(name) || isLocalPath(name)) {
31	      return null
32	    }
33	    registry = "@shadcn"
34	  }
35	
36	  const registries = { ...BUILTIN_REGISTRIES, ...config?.registries }
37	  const registryConfig = registries[registry]
38	  if (!registryConfig) {
39	    throw new RegistryNotConfiguredError(registry)
40	  }
41	
42	  // TODO: I don't like this here.
43	  // But this will do for now.
44	  validateRegistryConfig(registry, registryConfig)
45	
46	  return {
47	    url: buildUrlFromRegistryConfig(item, registryConfig, config),
48	    headers: buildHeadersFromRegistryConfig(registryConfig),
49	  }
50	}
51	
52	export function buildUrlFromRegistryConfig(
53	  item: string,
54	  registryConfig: z.infer<typeof registryConfigItemSchema>,
55	  config?: Config
56	) {
57	  if (typeof registryConfig === "string") {
58	    let url = registryConfig.replace(NAME_PLACEHOLDER, item)
59	    if (config?.style && url.includes(STYLE_PLACEHOLDER)) {
60	      url = url.replace(STYLE_PLACEHOLDER, config.style)
61	    }
62	    return expandEnvVars(url)
63	  }
64	
65	  let baseUrl = registryConfig.url.replace(NAME_PLACEHOLDER, item)
66	  if (config?.style && baseUrl.includes(STYLE_PLACEHOLDER)) {
67	    baseUrl = baseUrl.replace(STYLE_PLACEHOLDER, config.style)
68	  }
69	  baseUrl = expandEnvVars(baseUrl)
70	
71	  if (!registryConfig.params) {
72	    return baseUrl
73	  }
74	
75	  return appendQueryParams(baseUrl, registryConfig.params)
76	}
77	
78	export function buildHeadersFromRegistryConfig(
79	  config: z.infer<typeof registryConfigItemSchema>
80	) {
81	  if (typeof config === "string" || !config.headers) {
82	    return {}
83	  }
84	
85	  const headers: Record<string, string> = {}
86	
87	  for (const [key, value] of Object.entries(config.headers)) {
88	    const expandedValue = expandEnvVars(value)
89	
90	    if (shouldIncludeHeader(value, expandedValue)) {
91	      headers[key] = expandedValue
92	    }
93	  }
94	
95	  return headers
96	}
97	
98	function appendQueryParams(baseUrl: string, params: Record<string, string>) {
99	  const urlParams = new URLSearchParams()
100	
101	  for (const [key, value] of Object.entries(params)) {
102	    const expandedValue = expandEnvVars(value)
103	    if (expandedValue) {
104	      urlParams.append(key, expandedValue)
105	    }
106	  }
107	
108	  const queryString = urlParams.toString()
109	  if (!queryString) {
110	    return baseUrl
111	  }
112	
113	  const separator = baseUrl.includes(QUERY_PARAM_SEPARATOR)
114	    ? QUERY_PARAM_DELIMITER
115	    : QUERY_PARAM_SEPARATOR
116	
117	  return `${baseUrl}${separator}${queryString}`
118	}
119	
120	function shouldIncludeHeader(originalValue: string, expandedValue: string) {
121	  const trimmedExpanded = expandedValue.trim()
122	
123	  if (!trimmedExpanded) {
124	    return false
125	  }
126	
127	  // If the original value contains valid env vars, only include if expansion changed the value.
128	  if (originalValue.includes("${")) {
129	    // Check if there are actual env vars in the string
130	    const envVars = originalValue.match(ENV_VAR_PATTERN)
131	    if (envVars) {
132	      const templateWithoutVars = originalValue
133	        .replace(ENV_VAR_PATTERN, "")
134	        .trim()
135	      return trimmedExpanded !== templateWithoutVars
136	    }
137	  }
138	
139	  return true
140	}
141	
142	/**
143	 * Resolves a registry URL from a path or URL string.
144	 * Handles special cases like v0 registry URLs that need /json suffix.
145	 *
146	 * @param pathOrUrl - Either a relative path or a full URL
147	 * @returns The resolved registry URL
148	 */
149	export function resolveRegistryUrl(pathOrUrl: string) {
150	  if (isUrl(pathOrUrl)) {
151	    // If the url contains /chat/b/, we assume it's the v0 registry.
152	    // We need to add the /json suffix if it's missing.
153	    const url = new URL(pathOrUrl)
154	    if (url.pathname.match(/\/chat\/b\//) && !url.pathname.endsWith("/json")) {
155	      url.pathname = `${url.pathname}/json`
156	    }
157	
158	    return url.toString()
159	  }
160	
161	  return `${REGISTRY_URL}/${pathOrUrl}`
162	}
