## Step 2 — Context Setup (Dual Context)

Following the pattern in `carousel.tsx` (throw if context is missing) for root context, and `form.tsx` (empty-object default) for item context (because item context is read optionally by `StepperContent`).

```ts
const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue | null {
  return React.useContext(StepperItemContext)
}
```

`StepperItemContext` defaults to `null` rather than an empty object because `StepperContent` needs to differentiate "inside an item" from "standalone" — a truthy null check is cleaner than checking for empty objects.

---

## Step 3 — Controlled / Uncontrolled State Management

This follows React's standard pattern for uncontrolled-with-default. The internal `[internalValue, setInternalValue]` state is used when no external `value` prop is provided.

```ts
function Stepper({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalValue, setInternalValue] = React.useState<string>(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  // ... render
}
```

Key points:
- `isControlled` is derived from whether `controlledValue !== undefined` (not `null`), consistent with React controlled-component conventions.
- `onValueChange` is called in both controlled and uncontrolled modes, so consumers can respond to changes regardless.
- `defaultValue` defaults to `""` (empty string) — callers must pass a valid step value to have a step pre-selected at render.

