    value: "review",
    title: "Review",
    description: "Review and confirm",
    content: "Everything looks good! Confirm your details to complete setup.",
  },
]

export default function StepperDemo() {
  const [currentStep, setCurrentStep] = React.useState<string>("account")
  const [completedSteps, setCompletedSteps] = React.useState<Set<string>>(
    new Set()
  )

  const currentIndex = steps.findIndex((s) => s.value === currentStep)

  function handleNext() {
    setCompletedSteps((prev) => new Set([...prev, currentStep]))
    const next = steps[currentIndex + 1]
    if (next) {
      setCurrentStep(next.value)
    }
  }

  function handleBack() {
    const prev = steps[currentIndex - 1]
    if (prev) {
      setCurrentStep(prev.value)
    }
  }

  const isFirst = currentIndex === 0
  const isLast = currentIndex === steps.length - 1

  return (
    <div className="w-full max-w-xl">
      <Stepper value={currentStep} onValueChange={setCurrentStep}>
        <div className="flex items-center">
          {steps.map((step, index) => (
            <React.Fragment key={step.value}>
              <StepperItem
                value={step.value}
                completed={completedSteps.has(step.value)}
              >
                <StepperTrigger aria-label={step.title}>
                  {completedSteps.has(step.value) ? (
                    <CheckIcon className="size-4" />
                  ) : (
                    <span>{index + 1}</span>
                  )}
                </StepperTrigger>
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </StepperItem>
              {index < steps.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </div>

        {steps.map((step) => (
          <StepperContent key={step.value} value={step.value}>
            <div className="rounded-lg border p-4 text-sm text-muted-foreground">
              {step.content}
            </div>
          </StepperContent>
        ))}

        <div className="flex justify-between pt-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleBack}
            disabled={isFirst}
          >
            Back
          </Button>
          <Button size="sm" onClick={handleNext} disabled={isLast}>
            {isLast ? "Finish" : "Next"}
          </Button>
        </div>
      </Stepper>
    </div>
  )
}
```

Design notes:
- The items row is wrapped in `<div className="flex items-center">`. This wrapping div gets `items-center` so the `StepperSeparator` line aligns with the trigger circles' vertical midpoint.
- `StepperSeparator` is rendered with `React.Fragment` keyed on step value, placed between items by index guard.
- `StepperContent` uses the standalone pattern (own `value` prop), all placed after the items row inside the `Stepper` root. This is the cleaner demo pattern for horizontal orientation.
- Navigation buttons sit in a footer row, also inside `<Stepper>` (so it's all one self-contained block).
- The "Finish" label on the last step gives the demo a clear endpoint.
- `completedSteps` is a `Set<string>` updated when "Next" is clicked; the check icon renders for any step in that set.

