## `stepper.tsx` — Full Implementation

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
}

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

type StepperItemContextValue = {
  value: string
  disabled: boolean
  completed: boolean
}

// ─── Root Context ─────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── Item Context ─────────────────────────────────────────────────────────────

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue | null {
  return React.useContext(StepperItemContext)
}

// ─── Components ───────────────────────────────────────────────────────────────

function Stepper({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalValue, setInternalValue] = React.useState<string>(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("group/stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  value,
  disabled = false,
  completed = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  return (
    <StepperItemContext.Provider value={{ value, disabled, completed }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : "inactive"}
        {...(completed ? { "data-completed": "" } : {})}
        {...(disabled ? { "data-disabled": "" } : {})}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-col items-center gap-2"
            : "flex-row items-start gap-3",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { value: activeValue, onValueChange } = useStepper()
  const itemContext = useStepperItem()

  if (!itemContext) {
    throw new Error("StepperTrigger must be used within a <StepperItem />")
  }

  const { value, disabled, completed } = itemContext
  const isActive = activeValue === value

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : "inactive"}
      {...(completed ? { "data-completed": "" } : {})}
      {...(disabled ? { "data-disabled": "" } : {})}
      disabled={disabled}
      onClick={() => {
        if (!disabled) {
          onValueChange(value)
        }
      }}
      className={cn(
        "inline-flex size-8 shrink-0 cursor-pointer items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "border-muted-foreground/30 text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[completed]:border-primary data-[completed]:bg-primary data-[completed]:text-primary-foreground",
        "disabled:cursor-not-allowed disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none",
        "group-data-[orientation=horizontal]/stepper-item:text-center",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "text-xs text-muted-foreground",
        "group-data-[orientation=horizontal]/stepper-item:text-center",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "bg-border transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-px flex-1 self-auto"
          : "ms-4 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  value: valueProp,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { value?: string }) {
  const { value: activeValue } = useStepper()
  const itemContext = useStepperItem()

  const resolvedValue = itemContext?.value ?? valueProp

  if (resolvedValue === undefined) {
    throw new Error(
      "StepperContent requires a value prop when used outside of a <StepperItem />"
    )
  }

  if (activeValue !== resolvedValue) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}
```

