        type: "registry:example",
      },
    ],
  },
  {
    name: "switch-demo",
```

---

## Key Design Decisions

| Decision | Rationale |
|----------|-----------|
| No Radix UI dependency | No Radix primitive for steppers exists; React context is sufficient |
| Dual context (`StepperContext` + `StepperItemContext`) | Root context for orientation/active-step; item context for per-step value/state — mirrors `form.tsx` |
| `StepperContent` accepts optional `value` prop | Enables standalone use (horizontal demo) without requiring nesting inside `StepperItem` |
| `data-[completed]:` separate from `data-[state=active]:` | Completed and active are independent states (a completed step can be revisited/active again) |
| `StepperSeparator` reads orientation from context | Renders `h-px flex-1` (horizontal) vs `ms-4 w-px self-stretch` (vertical) automatically |
| `ms-4` on vertical separator | Aligns the 1px line under the center of the `size-8` (32px) trigger circle (16px = half of 32px) |

---

## Verification

1. **TypeScript**: Run `pnpm tsc --noEmit` in `apps/v4` — no errors in the two new files
2. **Registry validation**: Run `pnpm build` or the registry schema check — both new entries must pass `z.array(registryItemSchema).parse(...)`
3. **Uncontrolled**: Render `<Stepper defaultValue="account">` — clicking `StepperTrigger` should change active step without external state
4. **Controlled**: Render with `value={currentStep} onValueChange={setCurrentStep}` — step follows React state
5. **Completed styling**: `data-[completed]:bg-primary` on `StepperTrigger` renders filled primary color
6. **Vertical orientation**: Pass `orientation="vertical"` — items render `flex-row`, separator renders as `w-px` vertical line
7. **`StepperContent` dual-mode**: (a) inside `<StepperItem>` with no `value` prop — reads from item context; (b) standalone with `value="account"` — shows/hides correctly
8. **Error boundaries**: `useStepper()` throws outside `<Stepper>`; `StepperTrigger` throws outside `<StepperItem>`; `StepperContent` throws with no value source
9. **Alphabetical order**: Confirm "stepper" sits between "spinner" (line 554) and "switch" (line 565) in `ui/_registry.ts`; confirm "stepper-demo" sits between "spinner-item" (line 2115) and "switch-demo" (line 2126) in `examples/_registry.ts`

