"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: StepperOrientation
}

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

type StepperItemContextValue = {
  value: string
  disabled: boolean
  completed: boolean
}

// ─── Root Context ─────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── Item Context ─────────────────────────────────────────────────────────────

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue | null {
  return React.useContext(StepperItemContext)
}

// ─── Components ───────────────────────────────────────────────────────────────

function Stepper({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalValue, setInternalValue] = React.useState<string>(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("group/stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  value,
  disabled = false,
  completed = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
  disabled?: boolean
  completed?: boolean
}) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  return (
    <StepperItemContext.Provider value={{ value, disabled, completed }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : "inactive"}
        {...(completed ? { "data-completed": "" } : {})}
        {...(disabled ? { "data-disabled": "" } : {})}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-col items-center gap-2"
            : "flex-row items-start gap-3",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { value: activeValue, onValueChange } = useStepper()
  const itemContext = useStepperItem()

  if (!itemContext) {
    throw new Error("StepperTrigger must be used within a <StepperItem />")
  }

  const { value, disabled, completed } = itemContext
  const isActive = activeValue === value

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : "inactive"}
      {...(completed ? { "data-completed": "" } : {})}
      {...(disabled ? { "data-disabled": "" } : {})}
