  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    value: "account",
    title: "Account",
    description: "Create your account",
    content: "Enter your email and choose a secure password to get started.",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Set up your profile",
    content: "Add your name, bio, and profile picture so others can find you.",
  },
  {
    value: "review",
    title: "Review",
    description: "Confirm details",
    content:
      "Everything looks good! Confirm your details to complete the setup.",
  },
]

export default function StepperDemo() {
  const [currentStep, setCurrentStep] = React.useState<string>("account")
  const [completedSteps, setCompletedSteps] = React.useState<Set<string>>(
    new Set()
  )

  const currentIndex = steps.findIndex((s) => s.value === currentStep)
  const isFirst = currentIndex === 0
  const isLast = currentIndex === steps.length - 1

  function handleNext() {
    setCompletedSteps((prev) => new Set([...prev, currentStep]))
    const next = steps[currentIndex + 1]
    if (next) setCurrentStep(next.value)
  }

  function handleBack() {
    const prev = steps[currentIndex - 1]
    if (prev) setCurrentStep(prev.value)
  }

  return (
    <div className="w-full max-w-xl">
      <Stepper value={currentStep} onValueChange={setCurrentStep}>
        <div className="flex items-center">
          {steps.map((step, index) => (
            <React.Fragment key={step.value}>
              <StepperItem
                value={step.value}
                completed={completedSteps.has(step.value)}
              >
                <StepperTrigger aria-label={step.title}>
                  {completedSteps.has(step.value) ? (
                    <CheckIcon className="size-4" />
                  ) : (
                    <span>{index + 1}</span>
                  )}
                </StepperTrigger>
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </StepperItem>
              {index < steps.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </div>

        {steps.map((step) => (
          <StepperContent key={step.value} value={step.value}>
            <div className="rounded-lg border p-4 text-sm text-muted-foreground">
              {step.content}
            </div>
          </StepperContent>
        ))}

        <div className="flex justify-between pt-2">
          <Button
            variant="outline"
            size="sm"
            onClick={handleBack}
            disabled={isFirst}
          >
            Back
          </Button>
          <Button size="sm" onClick={handleNext} disabled={isLast}>
            {isLast ? "Finish" : "Next"}
          </Button>
        </div>
      </Stepper>
    </div>
  )
}

